// --- Email vindo do node "trigger" (flat) ou do próprio item atual como fallback
const emailTrigger = String(
  $node["trigger"]?.json?.email ?? $json?.email ?? ""
).trim().toLowerCase();

if (!emailTrigger) {
  return [{ json: { error: "email ausente no trigger" } }];
}

// --- Todos os items que chegam neste Code (devem ser os eventos)
const items = await $input.all();

// --- Mantém só eventos onde attendees contém o e-mail do trigger
const filtrados = items.filter(it => {
  const attendees = it.json?.attendees;
  return Array.isArray(attendees) &&
    attendees.some(a => String(a.email || "").trim().toLowerCase() === emailTrigger);
});

// --- Saída
return filtrados;

// Entram aqui os eventos já filtrados (cada item = 1 evento)
const items = await $input.all();

if (!items.length) {
  return [{ json: { mensagem: "Não encontrei eventos para esse e-mail.", eventos: [] } }];
}

const TZ = "America/Sao_Paulo";

// helpers
const toDate = (d) => d ? new Date(d) : null;
const sameYmd = (a, b) => a.toLocaleString("sv-SE", { timeZone: TZ }).slice(0,10) === b.toLocaleString("sv-SE", { timeZone: TZ }).slice(0,10);

// hoje (SP)
const agora = new Date();
const hojeSP = new Date(new Date().toLocaleString("en-US", { timeZone: TZ }));

// normaliza -> filtra inválidos -> filtra futuros e não-hoje -> ordena
const normalizados = items
  .map((it) => it.json)
  .map((ev) => {
    const start = toDate(ev.start?.dateTime || ev.start);
    const end   = toDate(ev.end?.dateTime   || ev.end);
    return { ev, start, end, tz: ev.start?.timeZone || TZ };
  })
  .filter(x => x.ev?.id && x.start instanceof Date && !isNaN(x.start))
  .filter(x => x.start > agora && !sameYmd(x.start, hojeSP))
  .sort((a, b) => a.start - b.start);

if (!normalizados.length) {
  return [{ json: { mensagem: "Não há eventos futuros (exceto hoje).", eventos: [] } }];
}

function fmtLinha(x, i) {
  const ev = x.ev;
  const tz = x.tz;
  const s = x.start;
  const e = x.end instanceof Date && !isNaN(x.end) ? x.end : null;

  const dia   = s.toLocaleDateString("pt-BR", { timeZone: tz });
  const hIni  = s.toLocaleTimeString("pt-BR", { timeZone: tz, hour: "2-digit", minute: "2-digit" });
  const hFim  = e ? e.toLocaleTimeString("pt-BR", { timeZone: tz, hour: "2-digit", minute: "2-digit" }) : null;

  return {
    numero: i + 1,
    id: ev.id,
    assunto: ev.summary || "Sem título",
    dia,
    horaInicio: hIni,
    horaFim: hFim,
    timezone: tz,
    link: ev.htmlLink || ev.hangoutLink || null,
  };
}

const essenciais = normalizados.map(fmtLinha);

// monta mensagem (limita a 10 linhas para não estourar UI)
const linhasMsg = essenciais.slice(0, 10).map(e =>
  `${e.numero} - ${e.assunto}, ${e.dia}, ${e.horaInicio}${e.horaFim ? "-" + e.horaFim : ""}, id ${e.id}`
);

const mensagem =
  `Temos os seguintes eventos nesse e-mail:\n\n` +
  linhasMsg.join("\n") +
  `\n\nMe informe o número do evento que você deseja alterar ou cancelar.`;

return [{
  json: {
    mensagem,
    eventos: essenciais,
    numeroParaId: Object.fromEntries(essenciais.map(e => [String(e.numero), e.id]))
  }
}];

// === Pega a agenda (objeto único) ===
const agenda = $node["Definir Agenda"].json;

// === Timezone configurado na agenda ===
const tz = agenda.timezone || "America/Sao_Paulo";

// === Pega todos os eventos (array de items) ===
const eventosRaw = $items("Disponibilidade do Google Calendar").map(item => item.json);

// ---- Função correta para normalizar datas no fuso horário certo ----
function toTZ(dateString, tz) {
  return new Date(
    new Date(dateString).toLocaleString("en-US", { timeZone: tz })
  );
}

// Normaliza eventos garantindo timezone coerente
const eventos = (eventosRaw || [])
  .filter(ev => ev?.start?.dateTime && ev?.end?.dateTime)
  .map(ev => ({
    start: toTZ(ev.start.dateTime, tz),
    end: toTZ(ev.end.dateTime, tz),
  }));

const intervaloMin = agenda.timeBetweenMeetingsMinutes;
const diasSemana = { DOM: 0, SEG: 1, TER: 2, QUA: 3, QUI: 4, SEX: 5, SAB: 6 };

// TZ e string do dia corrente (YYYY-MM-DD) no fuso da agenda
const hojeStr = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(0,10);

// Função auxiliar: próxima data para um dia da semana (pode retornar hoje)
function getProximaData(dia) {
  const hoje = new Date();
  let data = toTZ(hoje, tz);
  while (data.getDay() !== diasSemana[dia]) {
    data.setDate(data.getDate() + 1);
  }
  return data;
}

// === Geração dos slots disponíveis ===
let slotsLivres = [];

for (const dia of agenda.schedule) {
  if (!dia.available) continue;

  const dataAlvo = getProximaData(dia.day);

  // Garante que hours seja sempre array
  const faixas = Array.isArray(dia.hours) ? dia.hours : [dia.hours];

  for (const faixa of faixas) {
    const [hIni, mIni] = faixa.after.split(":").map(Number);
    const [hFim, mFim] = faixa.before.split(":").map(Number);

    // Ajusta datas com o fuso correto
    const inicioDia = toTZ(dataAlvo, tz);
    inicioDia.setHours(hIni, mIni, 0, 0);

    const fimDia = toTZ(dataAlvo, tz);
    fimDia.setHours(hFim, mFim, 0, 0);

    let current = new Date(inicioDia);

    while (current < fimDia) {
      const next = new Date(current.getTime() + intervaloMin * 60000);
      if (next > fimDia) break;

      // --- Libera slots de hoje apenas se faltarem >= 30 minutos ---
      const currentDiaStr = current.toLocaleString("sv-SE", { timeZone: tz }).slice(0,10);

      if (currentDiaStr === hojeStr) {
        const agora = new Date();
        const agoraTZ = toTZ(agora, tz);
        const limite = new Date(agoraTZ.getTime() + 30 * 60000);

        if (current < limite) {
          current = next;
          continue;
        }
      }

      // Checa conflito com eventos
      const ocupado = eventos.some(ev => current < ev.end && next > ev.start);

      if (!ocupado) {
        slotsLivres.push({
          day: dia.day,
          start: current.toISOString(),
          end: next.toISOString(),
        });
      }

      current = next;
    }
  }
}

return slotsLivres;

// === Pega a agenda (objeto único) ===
const agenda = $node["Definir Agenda"].json;

// === Timezone configurado na agenda ===
const tz = agenda.timezone || "America/Sao_Paulo";

// === Pega todos os eventos (array de items) ===
const eventosRaw = $items("Obter Eventos do Google Calendar").map(item => item.json);

// ---- Função correta para normalizar datas no fuso horário certo ----
function toTZ(dateString, tz) {
  return new Date(
    new Date(dateString).toLocaleString("en-US", { timeZone: tz })
  );
}

// Normaliza eventos garantindo timezone coerente
const eventos = (eventosRaw || [])
  .filter(ev => ev?.start?.dateTime && ev?.end?.dateTime)
  .map(ev => ({
    start: toTZ(ev.start.dateTime, tz),
    end: toTZ(ev.end.dateTime, tz),
  }));

const intervaloMin = agenda.timeBetweenMeetingsMinutes;
const diasSemana = { DOM: 0, SEG: 1, TER: 2, QUA: 3, QUI: 4, SEX: 5, SAB: 6 };

// TZ e string do dia corrente (YYYY-MM-DD) no fuso da agenda
const hojeStr = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(0,10);

// Função auxiliar: próxima data para um dia da semana (pode retornar hoje)
function getProximaData(dia) {
  const hoje = new Date();
  let data = toTZ(hoje, tz);
  while (data.getDay() !== diasSemana[dia]) {
    data.setDate(data.getDate() + 1);
  }
  return data;
}

// === Geração dos slots disponíveis ===
let slotsLivres = [];

for (const dia of agenda.schedule) {
  if (!dia.available) continue;

  const dataAlvo = getProximaData(dia.day);

  // Garante que hours seja sempre array
  const faixas = Array.isArray(dia.hours) ? dia.hours : [dia.hours];

  for (const faixa of faixas) {
    const [hIni, mIni] = faixa.after.split(":").map(Number);
    const [hFim, mFim] = faixa.before.split(":").map(Number);

    // Ajusta datas com o fuso correto
    const inicioDia = toTZ(dataAlvo, tz);
    inicioDia.setHours(hIni, mIni, 0, 0);

    const fimDia = toTZ(dataAlvo, tz);
    fimDia.setHours(hFim, mFim, 0, 0);

    let current = new Date(inicioDia);

    while (current < fimDia) {
      const next = new Date(current.getTime() + intervaloMin * 60000);
      if (next > fimDia) break;

      // --- Libera slots de hoje apenas se faltarem >= 30 minutos ---
      const currentDiaStr = current.toLocaleString("sv-SE", { timeZone: tz }).slice(0,10);

      if (currentDiaStr === hojeStr) {
        const agora = new Date();
        const agoraTZ = toTZ(agora, tz);
        const limite = new Date(agoraTZ.getTime() + 30 * 60000);

        if (current < limite) {
          current = next;
          continue;
        }
      }

      // Checa conflito com eventos
      const ocupado = eventos.some(ev => current < ev.end && next > ev.start);

      if (!ocupado) {
        slotsLivres.push({
          day: dia.day,
          start: current.toISOString(),
          end: next.toISOString(),
        });
      }

      current = next;
    }
  }
}

return slotsLivres;

// === Pega o 1º item do trigger (se o Code estiver em "Run Once for All Items")
const input = $items("trigger")[0].json;
// Se seu Code estiver em "Run Once for Each Item", use:
// const input = $json;

const { dia, horario, nome, empresa, email, telefone, descricao } = input;

// === TZ e "hoje" no fuso de SP ===
const tz = "America/Sao_Paulo";
const hojeStr = new Date().toLocaleString("sv-SE", { timeZone: tz }).slice(0, 10); // YYYY-MM-DD

// === Pega a lista de slots disponíveis e remove os de hoje ===
const slots = $items("Gerar Slots Livres")
  .map(item => item.json)
  .filter(slot => {
    const slotInicio = new Date(slot.start.replace("T", " ").replace(":00.000Z", ""));
    const slotDia = String(slot.start).slice(0, 10);

    const agora = new Date();
    const agoraTZ = new Date(agora.toLocaleString("en-US", { timeZone: tz }));
    const limite = new Date(agoraTZ.getTime() + 30 * 60000); // agora + 30min

    if (slotDia === hojeStr) {
      return slotInicio >= limite;
    }

    return slotDia > hojeStr;
  });

// Normaliza slot solicitado
const solicitadoKey = `${dia}T${horario}`;

// Procura o slot solicitado
const encontrado = slots.find(slot => {
  const sKey = String(slot.start).substring(0, 16);
  return sKey === solicitadoKey;
});

// Garante formato "YYYY-MM-DDTHH:MM:SS"
function toYYYYMMDDTHHMMSS(s) {
  return String(s).substring(0, 19);
}

// ======================================================
// == DEBUG PARA APARECER NO OUTPUT =====================
// ======================================================

const debug = {
  agora: new Date().toISOString(),
  hojeStr,
  solicitadoKey,
  slotsDepoisDoFiltro: slots.map(s => s.start),
  totalSlotsDepoisDoFiltro: slots.length,
  motivo: encontrado ? "slot encontrado" : "slot NAO encontrado"
};

// ======================================================
// == SE ENCONTROU O SLOT ===============================
// ======================================================

if (encontrado) {
  return [{
    json: {
      status: "ok",
      message: `Horário disponível: ${dia} ${horario}. Pode agendar.`,
      debug,  // <----- aparece no output
      dados: {
        nome,
        empresa,
        email,
        telefone,
        descricao,
        inicio: { dateTime: toYYYYMMDDTHHMMSS(encontrado.start), timeZone: tz },
        fim:    { dateTime: toYYYYMMDDTHHMMSS(encontrado.end),   timeZone: tz }
      }
    }
  }];
}

// ======================================================
// == SE NAO ENCONTROU, GERAR ALTERNATIVAS ==============
// ======================================================

// Agrupa slots por dia
const slotsPorDia = {};
for (const slot of slots) {
  const d = String(slot.start).split("T")[0];
  (slotsPorDia[d] ||= []).push(slot);
}

// Ordena dentro de cada dia
for (const d in slotsPorDia) {
  slotsPorDia[d].sort((a, b) => new Date(a.start) - new Date(b.start));
}

// Dias adjacentes
const solicitadoDia = dia;
const diaAnterior = new Date(`${dia}T00:00:00`);
diaAnterior.setDate(diaAnterior.getDate() - 1);
const diaSeguinte = new Date(`${dia}T00:00:00`);
diaSeguinte.setDate(diaSeguinte.getDate() + 1);

const prev = diaAnterior.toISOString().split("T")[0];
const next = diaSeguinte.toISOString().split("T")[0];

// Pega alternativas básicas
let alternativas = [
  ...(slotsPorDia[prev]?.slice(0, 2) || []),
  ...(slotsPorDia[solicitadoDia]?.slice(0, 2) || []),
  ...(slotsPorDia[next]?.slice(0, 2) || []),
];

// Expande até 7 dias
let offset = 2;
while (alternativas.length < 2 && offset <= 7) {
  const before = new Date(`${dia}T00:00:00`); before.setDate(before.getDate() - offset);
  const after  = new Date(`${dia}T00:00:00`); after.setDate(after.getDate() + offset);

  alternativas = [
    ...alternativas,
    ...(slotsPorDia[before.toISOString().split("T")[0]]?.slice(0, 2) || []),
    ...(slotsPorDia[after.toISOString().split("T")[0]]?.slice(0, 2) || []),
  ];
  offset++;
}

alternativas = alternativas.slice(0, 6).map(slot => ({
  inicio: { dateTime: toYYYYMMDDTHHMMSS(slot.start), timeZone: tz },
  fim:    { dateTime: toYYYYMMDDTHHMMSS(slot.end),   timeZone: tz }
}));

return [{
  json: {
    status: "indisponivel",
    message: `O horário ${dia} ${horario} não está disponível.`,
    debug,     // <----- debug aparece no output
    alternativas
  }
}];
